import zeep

# URL of the WSDL file provided by the third-party service
wsdl_url = "http://example.com/insurance_service?wsdl"

# Create a client instance with zeep
client = zeep.Client(wsdl=wsdl_url)

def lookup_policy(policy_number=None, customer_name=None):
    if policy_number and customer_name:
        # Construct SOAP XML body
        xml_body = """
            <soap:Envelope xmlns:soap="http://www.w3.org/2003/05/soap-envelope/"
                            xmlns:ins="http://example.com/insurance_service">
                <soap:Body>
                    <ins:LookupPolicyRequest>
                        <policyNumber>{}</policyNumber>
                        <customerName>{}</customerName>
                    </ins:LookupPolicyRequest>
                </soap:Body>
            </soap:Envelope>
        """.format(policy_number, customer_name)

        # Use zeep to send the SOAP request
        response = client.service.LookupPolicy(xml_body)

        return response

    else:
        print("Please provide both policy number and customer name.")

if __name__ == "__main__":
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    result = lookup_policy(policy_number, customer_name)
    print(result)